pd\\nfrom datetime import datetime, timedelta\\nimport warnings\\nwarnings.filterwarnings('ignore')\\n\\ndef get_chinext_stocks():\\n    \\\"\\\"\\\"获取创业板股票列表\\\"\\\"\\\"\\n    try:\\n        stock_info = ak.stock_info_a_code_name()\\n        chinext = stock_info[stock_info['code'].str.startswith('300')]\\n        return chinext['code'].tolist()\\n    except Exception as e:\\n        print(f\\\"获取创业板股票列表失败: {e}\\\")\\n        return []\\n\\ndef get_stock_data(stock_code, end_date='2024-04-08'):\\n    \\\"\\\"\\\"获取股票历史数据\\\"\\\"\\\"\\n    try:\\n        # 获取60个交易日的数据\\n        start_date = (datetime.strptime(end_date, '%Y-%m-%d') - timedelta(days=90)).strftime('%Y-%m-%d')\\n        df = ak.stock_zh_a_hist(symbol=stock_code, period=\\\"daily\\\", \\n                                start_date=start_date, end_date=end_date, adjust=\\\"qfq\\\")\\n        if df is None or len(df) < 25:\\n            return None\\n        \\n        # 重命名列\\n        df = df.rename(columns={\\n            '日期': 'date',\\n            '开盘': 'open',\\n            '收盘': 'close',\\n            '最高': 'high',\\n            '最低': 'low',\\n            '成交量': 'volume'\\n        })\\n        df['date'] = pd.to_datetime(df['date'])\\n        df = df.sort_values('date')\\n        return df\\n    except Exception as e:\\n        return None\\n\\ndef check_bullish_sandwich(df, idx):\\n    \\\"\\\"\\\"\\n    检查从idx开始的3日是否满足两阳夹一阴形态\\n    返回: (是否满足, 成交量比1, 成交量比2)\\n    \\\"\\\"\\\"\\n    if idx + 2 >= len(df) or idx < 1:\\n        return False, 0, 0\\n    \\n    # 获取4日数据（需要前一天计算涨跌幅）\\n    day0 = df.iloc[idx - 1]  # 第1天的前一天\\n    day1 = df.iloc[idx]      # 第1天\\n    day2 = df.iloc[idx + 1]  # 第2天\\n    day3 = df.iloc[idx + 2]  # 第3天\\n    \\n    # 条件1：第1、3日为阳线且涨幅>2%，第2日为阴线但跌幅<1%\\n    is_day1_bullish = day1['close'] > day1['open']\\n    is_day3_bullish = day3['close'] > day3['open']\\n    is_day2_bearish = day2['close'] < day2['open']\\n    \\n    day1_change = (day1['close'] - day0['close']) / day0['close'] * 100\\n    day2_change = (day2['close'] - day1['close']) / day1['close'] * 100\\n    day3_change = (day3['close'] - day2['close']) / day2['close'] * 100\\n    \\n    if not (is_day1_bullish and day1_change > 2):\\n        return False, 0, 0\\n    if not (is_day2_bearish and day2_change > -1):\\n        return False, 0, 0\\n    if not (is_day3_bullish and day3_change > 2):\\n        return False, 0, 0\\n    \\n    # 条件2：第3日实体完全吞没第2日实体\\n    engulfing = (day3['close'] > day2['open']) and (day3['open'] < day2['close'])\\n    if not engulfing:\\n        return False, 0, 0\\n    \\n    # 条件3：成交量逐步放大\\n    vol_ratio1 = day2['volume'] / day1['volume'] if day1['volume'] > 0 else 0\\n    vol_ratio2 = day3['volume'] / day2['volume'] if day2['volume'] > 0 else 0\\n    \\n    if vol_ratio1 <= 1.0 or vol_ratio2 <= 1.0:\\n        return False, 0, 0\\n    \\n    # 条件4：均线多头排列（在第3天验证）\\n    end_idx = idx + 3\\n    if end_idx + 17 > len(df):\\n        return False, 0, 0\\n    \\n    # 计算第3天的均线\\n    ma5 = df.iloc[end_idx-5:end_idx]['close'].mean()\\n    ma10 = df.iloc[end_idx-10:end_idx]['close'].mean()\\n    ma20 = df.iloc[end_idx-20:end_idx]['close'].mean()\\n    \\n    if not (ma5 > ma10 > ma20):\\n        return False, 0, 0\\n    \\n    return True, vol_ratio1, vol_ratio2\\n\\ndef scan_stock(code, end_date='2024-04-08'):\\n    \\\"\\\"\\\"扫描单只股票\\\"\\\"\\\"\\n    df = get_stock_data(code, end_date)\\n    if df is None:\\n        return []\\n    \\n    # 找到截止日期的索引\\n    target_date = pd.Timestamp(end_date)\\n    target_idx = None\\n    for i in range(len(df)-1, -1, -1):\\n        if df.iloc[i]['date'] <= target_date:\\n            target_idx = i\\n            break\\n    \\n    if target_idx is None or target_idx < 20:\\n        return []\\n    \\n    results = []\\n    # 扫描前20个交易日\\n    start_idx = max(20, target_idx - 19)\\n    \\n    for i in range(start_idx, target_idx - 1):\\n        is_pattern, vol_ratio1, vol_ratio2 = check_bullish_sandwich(df, i)\\n        if is_pattern:\\n            pattern_date = df.iloc[i]['date'].strftime('%Y-%m-%d')\\n            results.append({\\n                'code': code,\\n                'date': pattern_date,\\n                'vol_ratio1': f\\\"{vol_ratio1:.2f}\\\",\\n                'vol_ratio2': f\\\"{vol_ratio2:.2f}\\\"\\n            })\\n    \\n    return results\\n\\n# 主程序\\nprint(\\\"开始扫描创业板股票（2024-04-08前20个交易日）...\\\")\\n\\nchinext_codes = get_chinext_stocks()\\nprint(f\\\"获取到 {len(chinext_codes)} 只创业板股票\\\")\\n\\nall_results = []\\nvalid_stocks = 0\\n\\nfor i, code in enumerate(chinext_codes):\\n    if i % 100 == 0:\\n        print(f\\\"进度: {i}/{len(chinext_codes)}, 已找到 {len(all_results)} 个形态\\\")\\n    \\n    results = scan_stock(code, '2024-04-08')\\n    if results:\\n        valid_stocks += 1\\n    all_results.extend(results)\\n\\n# 输出结果\\noutput_path = \\\"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_22_bullish_sandwich/revised/ga/bullish_sandwich.txt\\\"\\n\\nwith open(output_path, 'w', encoding='utf-8') as f:\\n    if len(all_results) == 0:\\n        f.write(\\\"无符合条件的股票\\\\n\\\")\\n    else:\\n        for result in all_results:\\n            f.write(f\\\"{result['code']},{result['date']},{result['vol_ratio1']},{result['vol_ratio2']}\\\\n\\\")\\n\\nprint(f\\\"\\\\n扫描完成！\\\")\\nprint(f\\\"有效股票数: {valid_stocks}\\\")\\nprint(f\\\"找到形态数: {len(all_results)}\\\")\\nprint(f\\\"结果已保存到: {output_path}\\\")\\n\\nif all_results:\\n    print(f\\\"\\\\n结果示例:\\\")\\n    for result in all_results[:5]:\\n        print(f\\\"{result['code']},{result['date']},{result['vol_ratio1']},{result['vol_ratio2']}\\\")\\n```🛠️ **正在调用工具:** `code_run`  📥**参数:**\\n````text\\n{\\n  \\\"type\\\": \\\"python\\\",\\n  \\\"timeout\\\": 300\\n}\\n````\\n**LLM Running (Turn 3) ...**\\n\\n<summary>akshare扫描938只创业板2024-04-08历史数据，0个形态，与同行一致</summary>\\n\\n\\n\\n修订完成。使用akshare重新扫描了2024-04-08前20个交易日的创业板股票，结果与所有同行一致：**无符合条件的股票**。\\n\\n主要修改：\\n1. **数据源**：从mootdx改为aksha