日\n            df = df.tail(60).reset_index(drop=True)\n            \n            return df\n            \n        except Exception as e:\n            if attempt < max_retries - 1:\n                time.sleep(0.5)  # 短暂延迟后重试\n                continue\n            else:\n                return None\n    \n    return None\n\ndef calculate_ma(df, periods=[5, 10, 20]):\n    \"\"\"计算移动平均线\"\"\"\n    for period in periods:\n        df[f'ma{period}'] = df['close'].rolling(window=period).mean()\n    return df\n\ndef check_bullish_sandwich(df, i):\n    \"\"\"\n    检查第i天开始的连续3日是否满足两阳夹一阴形态\n    i: 第1天的索引\n    返回: (是否满足, 成交量比1, 成交量比2)\n    \"\"\"\n    if i + 2 >= len(df):\n        return False, None, None\n    \n    day1 = df.iloc[i]\n    day2 = df.iloc[i + 1]\n    day3 = df.iloc[i + 2]\n    \n    # 条件1: 第1日、第3日为阳线且涨幅>2%；第2日为阴线但跌幅<1%\n    # 阳线: 收盘价 > 开盘价\n    is_day1_bullish = day1['close'] > day1['open']\n    is_day3_bullish = day3['close'] > day3['open']\n    # 阴线: 收盘价 < 开盘价\n    is_day2_bearish = day2['close'] < day2['open']\n    \n    if not (is_day1_bullish and is_day3_bullish and is_day2_bearish):\n        return False, None, None\n    \n    # 计算涨跌幅（相对于前一日收盘价）","is_error":false}]},"parent_tool_use_id":null,"session_id":"289869ea-8040-4f35-b25d-a8ce1ec91cee","uuid":"67888bc4-6788-4570-8264-c6cb0e2776fe","timestamp":"2026-04-15T15:30:25.831Z","tool_use_result":{"stdout":"#!/usr/bin/env python3\n\"\"\"\n两阳夹一阴多方炮形态识别 - 改进版\nBullish Sandwich Pattern Detection - Improved Version with better error handling\n\"\"\"\n\nimport akshare as ak\nimport pandas as pd\nfrom datetime import datetime, timedelta\nimport warnings\nimport time\nwarnings.filterwarnings('ignore')\n\ndef get_chinext_stocks():\n    \"\"\"获取创业板股票列表\"\"\"\n    try:\n        stock_info = ak.stock_info_a_code_name()\n        # 创业板代码以300开头\n        chinext = stock_info[stock_info['code'].str.startswith('300')]\n        return chinext['code'].tolist()\n    except Exception as e:\n        print(f\"获取创业板股票列表失败: {e}\")\n  